external_knowledge:
; Growth rate is calculated as (current value - previous value) / previous value; 
; A high growth rate means the number of new positive cases is increasing rapidly; 
; The query assumes that the test dates are in chronological order.

sql:
SELECT SUM(total_tests_performed) AS total_tests
FROM testing_data
WHERE test_date = '2021-01-22';

SELECT total_tests_performed
FROM testing_data
WHERE test_date = '1' AND region_id = 1;

SELECT new_positives, total_tests_performed
FROM testing_data
WHERE test_date = '2023-01-01' AND site_id = 1;

SELECT SUM(new_positives) AS total_positive_cases
FROM testing_data
WHERE site_id = 0 AND test_date BETWEEN '2021-01-01' AND '2021-01-31';

SELECT test_date, new_positives, total_tests_performed
FROM testing_data
WHERE site_id = (SELECT site_id FROM testing_sites WHERE site_name = 'Downtown LA Testing Site');
